    ingredients:[{a:"1 kg",i:"Salmon fillet, sushi grade, skin on, deboned"},{a:"60 g",i:"coarse sea salt"},{a:"40 g",i:"sugar (cane sugar)"},{a:"1 tsp each",i:"white pepper, dill (fresh or dried)"},{a:"1 tsp",i:"lemon zest (optional)"}],
